/* REVIEWS WRAPPER — keeps the handoff Reviews module at the same
   1320px reading width as the other inner blocks, and defers paint
   until near the viewport. All visual styling lives in reviews.css
   (the handoff stylesheet, scoped under .reviews-section). */
.reviewsWrap {
  content-visibility: auto;
  contain-intrinsic-size: 0 600px;
}

/* SIMILAR PRODUCTS WRAPPER */
.similarWrap {
  margin-top: 5rem;
  /* Skip painting the entire similar-products grid until it's near the
     viewport. contain-intrinsic-size reserves the layout slot so scroll
     position and scrollbar height stay correct. */
  content-visibility: auto;
  contain-intrinsic-size: 0 800px;
}

/* LIGHTBOX */
.lightbox {
  position: fixed;
  inset: 0;
  z-index: 200;
  background: rgba(15, 15, 15, 0.92);
  display: none;
  align-items: center;
  justify-content: center;
  padding: 2rem;
  backdrop-filter: blur(10px);
}
.lightboxOpen {
  display: flex;
}
.lightbox img {
  max-width: 92%;
  max-height: 88%;
  border-radius: 16px;
  box-shadow: 0 30px 80px rgba(0, 0, 0, 0.5);
}
.lbBtn {
  position: absolute;
  background: rgba(255, 255, 255, 0.12);
  border: 1px solid rgba(255, 255, 255, 0.3);
  color: white;
  cursor: pointer;
  backdrop-filter: blur(8px);
  width: 48px;
  height: 48px;
  border-radius: 50%;
  display: grid;
  place-items: center;
}
.lbBtn:hover {
  background: rgba(255, 255, 255, 0.22);
}
.lbClose {
  top: 2rem;
  right: 2rem;
}
.lbPrev {
  left: 2rem;
  top: 50%;
  transform: translateY(-50%);
}
.lbNext {
  right: 2rem;
  top: 50%;
  transform: translateY(-50%);
}
.lbCounter {
  position: absolute;
  bottom: 2rem;
  left: 50%;
  transform: translateX(-50%);
  color: rgba(255, 255, 255, 0.85);
  font-family: var(--font-display);
  font-size: 0.75rem;
  letter-spacing: 0.2em;
}

/* LOADING / ERROR STATES */
.stateWrap {
  width: min(100%, 1320px);
  margin: 0 auto;
  padding: 8rem clamp(1rem, 4vw, 4rem) 4rem;
  min-height: 60vh;
  display: grid;
  place-items: center;
  text-align: center;
}
.stateTitle {
  font-family: var(--font-display);
  font-size: 1.5rem;
  color: var(--shila-ink);
  margin: 0 0 0.5rem;
}
.stateMsg {
  color: var(--shila-gray-3);
  margin: 0 0 1.25rem;
}
.retryBtn {
  display: inline-flex;
  align-items: center;
  gap: 0.4rem;
  padding: 0.65rem 1.25rem;
  background: var(--shila-ink);
  color: #fff;
  border: 0;
  border-radius: 999px;
  cursor: pointer;
  font-weight: 600;
  letter-spacing: 0.04em;
}
.retryBtn:hover {
  background: #333;
}

