    padding: 0.5rem 1rem;
    /* Use max-height for animatable values */
    height: auto;
    max-height: 55px;
    flex-wrap: wrap;
    align-content: flex-start;
    /* Keep overflow hidden - border stays visible */
    overflow: hidden;
    /* Reduce backdrop-filter for performance */
    backdrop-filter: blur(12px);
    -webkit-backdrop-filter: blur(12px);
    /* CSS containment for performance */
    contain: layout style;
    /* Smooth 1 second max-height animation + delayed shadow reappearance */
    transition:
      max-height 1s cubic-bezier(0.22, 1, 0.36, 1),
      box-shadow 0.3s ease 1s;
    /* 1s delay - shadow appears after collapse completes */
  }

  .headerExpanded {
    /* Expanded max-height - closer to actual content for symmetric animation */
    max-height: 280px;
    /* Reduce blur during animation for performance */
    backdrop-filter: blur(8px);
    -webkit-backdrop-filter: blur(8px);
    /* Remove shadow immediately when expanding (no delay) */
    box-shadow: none;
    transition:
      max-height 1s cubic-bezier(0.22, 1, 0.36, 1),
      box-shadow 0.1s ease 0s;
    /* 0s delay - shadow disappears immediately */
  }

  .rightSection {
    gap: 1rem;
  }

  .iconContainer {
    gap: 0.5rem;
    padding-left: 0.75rem;
  }

  .iconButton {
    padding: 0.5rem;
    width: 34px;
    height: 34px;
  }

  /* Mobile Profile Menu - GPU accelerated animation */
  .mobileProfileMenu {
    width: 100%;
    display: grid;
    grid-template-columns: 1fr 1fr;
    gap: 0.5rem;
    /* Collapsed: no padding/margin */
    padding-top: 0;
    margin-top: 0;
    border-top: 1px solid rgba(0, 0, 0, 0.08);
    position: relative;
    z-index: 50;
    /* GPU hints */
    contain: content;
    /* Hidden when collapsed */
    max-height: 0;
    opacity: 0;
    overflow: hidden;
    transition:
      max-height 1s cubic-bezier(0.22, 1, 0.36, 1),
      opacity 0.5s ease,
      padding-top 1s cubic-bezier(0.22, 1, 0.36, 1),
      margin-top 1s cubic-bezier(0.22, 1, 0.36, 1);
  }

  /* When header is expanded, reveal the menu */
  .headerExpanded .mobileProfileMenu {
    padding-top: 0.75rem;
    margin-top: 0.5rem;
    /* Closer to actual content height for symmetric animation */
    max-height: 220px;
    opacity: 1;
  }

  .mobileProfileLink {
    font-size: 0.875rem;
    font-weight: 500;
    color: #000000;
    padding: 0.6rem 0.75rem;
    border-radius: 8px;
    background: transparent;
    transition: background 0.15s ease;
    text-align: center;
    display: block;
    position: relative;
    z-index: 50;
  }

  .mobileProfileLink:hover,
  .mobileProfileLink:active {
    background: rgba(0, 0, 0, 0.05);
  }

  .mobileLogoutLink {
    font-size: 0.875rem;
    font-weight: 500;
    color: #dc2626;
    padding: 0.6rem 0.75rem;
    border-radius: 8px;
    background: transparent;
    border: none;
    cursor: pointer;
    text-align: center;
    width: 100%;
    transition: background 0.15s ease;
    position: relative;
    z-index: 50;
    grid-column: 1 / -1;
    margin-top: 0.25rem;
  }

  .mobileLogoutLink:hover,
  .mobileLogoutLink:active {
    background: rgba(220, 38, 38, 0.08);
  }

  .mobileDivider {
    grid-column: 1 / -1;
    height: 1px;
    background: rgba(0, 0, 0, 0.08);
    margin: 0.25rem 0;
  }
}

