138	    
139	    // Add very subtle pulse brightness (not too aggressive)
140	    float finalAlpha = baseAlpha * (1.0 + pulseBrightness * 0.25);
141	    
142	    // === EXTREME EXPLOSION PHYSICS ===
143	    if (u_explosion_time > 0.0) {
144	      // Longer explosion duration ~1.5 seconds for far-reaching effect
145	      float explosionProgress = min(u_explosion_time / 1.5, 1.0);
146	      
147	      // Multiple noise layers for HIGHLY random directions (total chaos!)
148	      float disperseAngle1 = fbm(vec2(uv.x * 15.0, uv.y * 12.0)) * 6.28;
149	      float disperseAngle2 = fbm(vec2(uv.y * 18.0, uv.x * 14.0 + u_explosion_time)) * 3.14;
150	      float finalAngle = disperseAngle1 + disperseAngle2; // Combined randomness
151	      
152	      vec2 disperseDirection = vec2(cos(finalAngle), sin(finalAngle));
153	      
154	      // EXTREME Physics: VERY fast initial explosion, then slow down
155	      float velocity = 12.0 * (1.0 - explosionProgress * 0.5); // SUPER fast burst!
156	      float disperseAmount = u_explosion_time * velocity;
157	      
158	      // Add acceleration curve for explosive feeling (fast start, then decelerate)
159	      float acceleration = 1.0 + pow(1.0 - explosionProgress, 3.0) * 2.0;
160	      disperseAmount *= acceleration;
161	      
162	      // EXTREME upward drift (smoke shoots upward dramatically)
163	      float upwardDrift = u_explosion_time * 5.0;
164	      
165	      // Add spin/rotation to particles (they rotate as they explode)
166	      float spin = u_explosion_time * 3.0;
167	      float spinAngle = fbm(uv * 20.0) * spin;
168	      mat2 rotation = mat2(cos(spinAngle), -sin(spinAngle), sin(spinAngle), cos(spinAngle));
169	      disperseDirection = rotation * disperseDirection;
170	      
171	      // Apply EXTREME displacement (particles fly FAR away!)
172	      vec2 explodedUV = uv + disperseDirection * disperseAmount * 1.5 + vec2(0.0, -upwardDrift * 0.5);
173	      
174	      // Slower fade out so explosion is visible longer
175	      float explosionFade = 1.0 - smoothstep(0.5, 1.0, explosionProgress);
176	      finalAlpha *= explosionFade;
177	      
178	      // Make particles expand dramatically and become very wispy
179	      float distance = length(explodedUV - uv);
180	      float edgeWisp = 1.0 - smoothstep(0.0, 1.0, distance * 1.5);
181	      finalAlpha *= mix(1.0, edgeWisp * 0.4, explosionProgress);
182	      
183	      // EXTREME particle break-up (heavy fragmentation)
184	      float breakup1 = fbm(explodedUV * 20.0 + vec2(u_explosion_time * 8.0, 0.0));
185	      float breakup2 = fbm(explodedUV * 30.0 - vec2(0.0, u_explosion_time * 6.0));
186	      float combinedBreakup = mix(breakup1, breakup2, 0.5);
187	      finalAlpha *= mix(1.0, combinedBreakup, explosionProgress * 0.9);
188	      
189	      // Add turbulence (chaotic movement)
190	      float turbulence = fbm(explodedUV * 10.0 + u_explosion_time * 4.0);
191	      finalAlpha *= mix(1.0, turbulence, explosionProgress * 0.6);
192	    }
193	    
194	    // Apply global intensity for fade in/out
195	    finalAlpha *= u_intensity;
196	    
197	    // Smoke color - darker and more visible
198	    vec3 smokeColor = vec3(0.08, 0.12, 0.18);
199	    
200	    // Very subtle color shift for pulse (barely noticeable)
201	    vec3 pulseColor = vec3(0.09, 0.13, 0.20);
202	    vec3 finalColor = mix(smokeColor, pulseColor, pulseBrightness * 0.2);
203	    
204	    gl_FragColor = vec4(finalColor, finalAlpha * 1.5);
205	  }
206	`;
207	
208	const NavLinkShaderOverlay = forwardRef<NavLinkShaderOverlayAPI, {}>((props, ref) => {
209	  const rootRef = useRef<HTMLDivElement | null>(null);
210	  const canvasRef = useRef<HTMLCanvasElement | null>(null);
211	  const glRef = useRef<WebGLRenderingContext | null>(null);
212	
213	  const [active, setActive] = useState<boolean>(false);
214	  const [canvasRect, setCanvasRect] = useState<CanvasRect | null>(null);
215	  const [webglSupported, setWebglSupported] = useState<boolean>(true);
216	  const devicePixelRatioRef = useRef<number>(typeof window !== 'undefined' ? window.devicePixelRatio || 1 : 1);
217	
218	  const programRef = useRef<{
219	    program: WebGLProgram;
220	    attribs: { a_pos: number };
221	    uniforms: {
222	      u_res: WebGLUniformLocation | null;
223	      u_time: WebGLUniformLocation | null;
224	      u_intensity: WebGLUniformLocation | null;
225	      u_progress: WebGLUniformLocation | null;
226	      u_explosion_time: WebGLUniformLocation | null;
227	    };
228	  } | null>(null);
229	  const positionBufferRef = useRef<WebGLBuffer | null>(null);
230	  const rafIdRef = useRef<number | null>(null);
231	  const startTimeRef = useRef<number>(typeof performance !== 'undefined' ? performance.now() : Date.now());
232	  const intensityRef = useRef<number>(0);
233	  const progressRef = useRef<number>(0);
234	  const explosionTimeRef = useRef<number>(0);
235	  const isExplodingRef = useRef<boolean>(false);
236	  const baseLinkRectRef = useRef<{ left: number; top: number; width: number; height: number } | null>(null);
237	
238	  const positionCanvasOverLink = useCallback((linkElement: HTMLElement) => {
239	    const linkRect = linkElement.getBoundingClientRect();
240	
241	    // Store base link rect for explosion calculations
242	    baseLinkRectRef.current = {
243	      left: linkRect.left,
244	      top: linkRect.bottom - 6,
245	      width: linkRect.width,
246	      height: 16
247	    };
248	
249	    // Update React state
250	    setCanvasRect(baseLinkRectRef.current);
251	
252	    // ALSO immediately apply via inline styles to avoid async delay
253	    const canvas = canvasRef.current;
254	    if (canvas) {
255	      canvas.style.left = `${Math.round(baseLinkRectRef.current.left)}px`;
256	      canvas.style.top = `${Math.round(baseLinkRectRef.current.top)}px`;
257	      canvas.style.width = `${Math.round(baseLinkRectRef.current.width)}px`;
258	      canvas.style.height = `${Math.round(baseLinkRectRef.current.height)}px`;
259	    }
260	  }, []);
261	
262	  useImperativeHandle(ref, () => ({
263	    beginHover(linkElement: HTMLElement) {
264	      // Cancel any ongoing explosion FIRST
265	      explosionTimeRef.current = 0;
266	      isExplodingRef.current = false;
267	
268	      // Clear inline styles BEFORE repositioning (critical!)
269	      const canvas = canvasRef.current;
270	      if (canvas) {
271	        canvas.style.left = '';
272	        canvas.style.top = '';
273	        canvas.style.width = '';
274	        canvas.style.height = '';
275	      }
276	
277	      // Now position canvas for new link
278	      positionCanvasOverLink(linkElement);
279	      setActive(true);
280	      progressRef.current = 0;
281	    },
282	    updatePointer(clientX: number, clientY: number) {
283	      // Not needed for nav links, but kept for API consistency
284	    },
285	    endHover() {
286	      setActive(false);
287	      // Trigger explosion state instead of normal fade
288	      isExplodingRef.current = true;
289	      explosionTimeRef.current = 0;
290	    },
291	  }), [positionCanvasOverLink]);
292	
293	  useLayoutEffect(() => {
294	    const canvas = canvasRef.current;
295	    if (!canvas) return;
296	
297	    const initWebGL = () => {
298	      const gl = canvas.getContext('webgl', {
299	        alpha: true,
300	        premultipliedAlpha: false,
301	        preserveDrawingBuffer: false,
302	        antialias: false,
303	        depth: false,
304	        stencil: false,
305	        powerPreference: 'high-performance',
306	      });
307	      if (!gl) {
308	        setWebglSupported(false);
309	        return;
310	      }
311	      glRef.current = gl;
312	
313	      gl.enable(gl.BLEND);
314	      gl.blendFunc(gl.SRC_ALPHA, gl.ONE_MINUS_SRC_ALPHA);
315	
316	      // Create quad buffer
317	      const positionBuffer = gl.createBuffer();
318	      if (!positionBuffer) return;
319	      positionBufferRef.current = positionBuffer;
320	      gl.bindBuffer(gl.ARRAY_BUFFER, positionBuffer);
321	      const positions = new Float32Array([
322	        -1, -1,
323	        1, -1,
324	        -1, 1,
325	        -1, 1,
326	        1, -1,
327	        1, 1,
328	      ]);
329	      gl.bufferData(gl.ARRAY_BUFFER, positions, gl.STATIC_DRAW);
330	
331	      // Compile shaders
332	      const vs = gl.createShader(gl.VERTEX_SHADER);
333	      const fs = gl.createShader(gl.FRAGMENT_SHADER);
334	      if (!vs || !fs) return;
335	
336	      gl.shaderSource(vs, vsSource);
337	      gl.compileShader(vs);
338	      if (!gl.getShaderParameter(vs, gl.COMPILE_STATUS)) return;
339	
340	      gl.shaderSource(fs, fsSource);
341	      gl.compileShader(fs);
342	      if (!gl.getShaderParameter(fs, gl.COMPILE_STATUS)) return;
343	
344	      const program = gl.createProgram();
345	      if (!program) return;
346	
347	      gl.attachShader(program, vs);
348	      gl.attachShader(program, fs);
349	      gl.linkProgram(program);
350	
351	      if (!gl.getProgramParameter(program, gl.LINK_STATUS)) return;
352	
353	      programRef.current = {
354	        program,
355	        attribs: {
356	          a_pos: gl.getAttribLocation(program, 'a_pos'),
357	        },
358	        uniforms: {
359	          u_res: gl.getUniformLocation(program, 'u_res'),
360	          u_time: gl.getUniformLocation(program, 'u_time'),
361	          u_intensity: gl.getUniformLocation(program, 'u_intensity'),
362	          u_progress: gl.getUniformLocation(program, 'u_progress'),
363	          u_explosion_time: gl.getUniformLocation(program, 'u_explosion_time'),
364	        },
365	      };
366	
367	      gl.deleteShader(vs);
368	      gl.deleteShader(fs);
369	
370	      // Initial clear
371	      gl.viewport(0, 0, gl.drawingBufferWidth, gl.drawingBufferHeight);
372	      gl.clearColor(0, 0, 0, 0);
373	      gl.clear(gl.COLOR_BUFFER_BIT);
374	    };
375	
376	    const handleContextLost = (e: Event) => {
377	      e.preventDefault();
378	      glRef.current = null;
379	      programRef.current = null;
380	      positionBufferRef.current = null;
381	    };
382	
383	    const handleContextRestored = () => {
384	      initWebGL();
385	    };
386	
387	    canvas.addEventListener('webglcontextlost', handleContextLost as EventListener, false);
388	    canvas.addEventListener('webglcontextrestored', handleContextRestored as EventListener, false);
389	
390	    initWebGL();
391	
392	    return () => {
393	      canvas.removeEventListener('webglcontextlost', handleContextLost as EventListener);
394	      canvas.removeEventListener('webglcontextrestored', handleContextRestored as EventListener);
395	      const gl = glRef.current;
396	      if (gl) {
397	        if (positionBufferRef.current) gl.deleteBuffer(positionBufferRef.current);
398	        if (programRef.current) gl.deleteProgram(programRef.current.program);
399	      }
400	      glRef.current = null;
401	      programRef.current = null;
402	      positionBufferRef.current = null;
403	    };
404	  }, []);
405	
406	  // DPR-aware sizing
407	  useEffect(() => {
408	    const canvas = canvasRef.current;
409	    const gl = glRef.current;
410	    if (!canvas || !gl || !canvasRect) return;
411	
412	    const dpr = devicePixelRatioRef.current;
413	    const targetWidth = Math.max(1, Math.floor(canvasRect.width * dpr));
414	    const targetHeight = Math.max(1, Math.floor(canvasRect.height * dpr));
415	
416	    if (canvas.width !== targetWidth || canvas.height !== targetHeight) {
417	      canvas.width = targetWidth;
418	      canvas.height = targetHeight;
419	    }
420	    gl.viewport(0, 0, targetWidth, targetHeight);
421	
422	    if (programRef.current) {
423	      gl.useProgram(programRef.current.program);
424	      if (programRef.current.uniforms.u_res) {
425	        gl.uniform2f(programRef.current.uniforms.u_res, targetWidth, targetHeight);
426	      }
427	    }
428	
429	    gl.clearColor(0, 0, 0, 0);
430	    gl.clear(gl.COLOR_BUFFER_BIT);
431	  }, [canvasRect]);
432	
433	  // Monitor window resize
434	  useEffect(() => {
435	    const handleWindowResize = () => {
436	      devicePixelRatioRef.current = window.devicePixelRatio || 1;
437	      setCanvasRect(prev => (prev ? { ...prev } : prev));
438	    };
439	    window.addEventListener('resize', handleWindowResize);
440	    return () => window.removeEventListener('resize', handleWindowResize);
441	  }, []);
442	
443	  // Render loop
444	  useEffect(() => {
445	    const gl = glRef.current;
446	    const canvas = canvasRef.current;
447	    if (!gl || !canvas) return;
448	
449	    const EASING = 0.12;
450	    const PROGRESS_SPEED = 3.0;
451	    const EPS = 0.001;
452	
453	    let lastFrameTime = performance.now();
454	
455	    const render = () => {
456	      const now = typeof performance !== 'undefined' ? performance.now() : Date.now();
457	      const deltaTime = (now - lastFrameTime) * 0.001; // Delta in seconds
458	      lastFrameTime = now;
459	
460	      const elapsedSeconds = (now - startTimeRef.current) / 1000;
461	
462	      // === EXPLOSION STATE MACHINE ===
463	      if (isExplodingRef.current) {
464	        // Update explosion time
465	        explosionTimeRef.current += deltaTime;
466	
467	        // Keep intensity at 1 during explosion (shader handles the fade)
468	        intensityRef.current = 1.0;
469	        progressRef.current = 1.0; // Keep full progress during explosion
470	
471	        // EXPAND CANVAS DYNAMICALLY during explosion for visible effect
472	        // Update directly via ref to avoid React re-render jitter
473	        if (baseLinkRectRef.current && canvas) {
474	          const explosionProgress = Math.min(explosionTimeRef.current / 1.5, 1.0);
475	          // Expand to 3x width and 5x height (80px tall)
476	          const expandFactor = 1.0 + explosionProgress * 2.0; // 1x -> 3x
477	          const heightExpandFactor = 1.0 + explosionProgress * 4.0; // 16px -> 80px
478	
479	          const baseRect = baseLinkRectRef.current;
480	          const expandedWidth = baseRect.width * expandFactor;
481	          const expandedHeight = baseRect.height * heightExpandFactor;
482	
483	          // Center expansion around original position
484	          const leftOffset = (expandedWidth - baseRect.width) / 2;
485	          const topOffset = (expandedHeight - baseRect.height) / 2;
486	
487	          // Update canvas style directly (no React state = no jitter)
488	          canvas.style.left = `${Math.round(baseRect.left - leftOffset)}px`;
489	          canvas.style.top = `${Math.round(baseRect.top - topOffset)}px`;
490	          canvas.style.width = `${Math.round(expandedWidth)}px`;
491	          canvas.style.height = `${Math.round(expandedHeight)}px`;
492	        }
493	
494	        // Explosion completes after 1.5 seconds (longer for dramatic effect)
495	        if (explosionTimeRef.current >= 1.5) {
496	          isExplodingRef.current = false;
497	          explosionTimeRef.current = 0;
498	          progressRef.current = 0;
499	          intensityRef.current = 0;
500	
501	          // Clear inline styles before restoring via React state
502	          if (canvas) {
503	            canvas.style.left = '';
504	            canvas.style.top = '';
505	            canvas.style.width = '';
506	            canvas.style.height = '';
507	          }
508	
509	          // Restore original canvas size via state (end of animation, one-time update is fine)
510	          if (baseLinkRectRef.current) {
511	            setCanvasRect(baseLinkRectRef.current);
512	          }
513	        }
514	      } else {
515	        // Normal hover state management
516	        // Smooth intensity fade in/out
517	        const targetIntensity = active ? 1 : 0;
518	        intensityRef.current += (targetIntensity - intensityRef.current) * EASING;
519	        if (Math.abs(intensityRef.current - targetIntensity) < EPS) intensityRef.current = targetIntensity;
520	
521	        // Progress animation (grows from left to right)
522	        const deltaProgress = deltaTime * PROGRESS_SPEED;
523	        if (active) {
524	          progressRef.current = Math.min(1, progressRef.current + deltaProgress);
525	        } else {
526	          // Should not reach here if explosion is working
527	          progressRef.current = Math.max(0, progressRef.current - deltaProgress * 1.5);
528	        }
529	      }
530	
531	      // Clear frame
532	      gl.clearColor(0, 0, 0, 0);
533	      gl.clear(gl.COLOR_BUFFER_BIT);
534	
535	      const canvasWidth = canvas.width;
536	      const canvasHeight = canvas.height;
537	
538	      // Render if we have intensity OR if we're exploding
539	      if ((intensityRef.current > EPS || isExplodingRef.current) && programRef.current) {
540	        const bundle = programRef.current;
541	        gl.useProgram(bundle.program);
542	
543	        gl.bindBuffer(gl.ARRAY_BUFFER, positionBufferRef.current);
544	        if (bundle.attribs.a_pos >= 0) {
545	          gl.enableVertexAttribArray(bundle.attribs.a_pos);
546	          gl.vertexAttribPointer(bundle.attribs.a_pos, 2, gl.FLOAT, false, 0, 0);
547	        }
548	
549	        if (bundle.uniforms.u_res) gl.uniform2f(bundle.uniforms.u_res, canvasWidth, canvasHeight);
550	        if (bundle.uniforms.u_time) gl.uniform1f(bundle.uniforms.u_time, elapsedSeconds);
551	        if (bundle.uniforms.u_intensity) gl.uniform1f(bundle.uniforms.u_intensity, intensityRef.current);
552	        if (bundle.uniforms.u_progress) gl.uniform1f(bundle.uniforms.u_progress, progressRef.current);
553	        if (bundle.uniforms.u_explosion_time) gl.uniform1f(bundle.uniforms.u_explosion_time, explosionTimeRef.current);
554	
555	        gl.drawArrays(gl.TRIANGLES, 0, 6);
556	      }
557	
558	      // Schedule next frame only if needed (including during explosion)
559	      if (active || intensityRef.current > EPS || progressRef.current > EPS || isExplodingRef.current) {
560	        rafIdRef.current = requestAnimationFrame(render);
561	      } else {
562	        rafIdRef.current = null;
563	      }
564	    };
565	
566	    // Start loop if needed (including for explosion)
567	    if ((active || intensityRef.current > 0 || isExplodingRef.current) && rafIdRef.current == null) {
568	      rafIdRef.current = requestAnimationFrame(render);
569	    }
570	
571	    return () => {
572	      if (rafIdRef.current) {
573	        cancelAnimationFrame(rafIdRef.current);
574	        rafIdRef.current = null;
575	      }
576	    };
577	  }, [active, canvasRect]);
578	
579	
580	
581	  const style: React.CSSProperties = canvasRect
582	    ? {
583	      position: 'fixed',
584	      left: `${Math.round(canvasRect.left)}px`,
585	      top: `${Math.round(canvasRect.top)}px`,
586	      width: `${Math.round(canvasRect.width)}px`,
587	      height: `${Math.round(canvasRect.height)}px`,
588	      pointerEvents: 'none',
589	      zIndex: 2000,
590	      opacity: 1,
591	      filter: 'blur(2px)',
592	    }
593	    : { opacity: 0, pointerEvents: 'none' };
594	
595	  return (
596	    <div ref={rootRef} style={{ position: 'fixed', top: 0, left: 0, width: '100%', height: '100%', pointerEvents: 'none', zIndex: 2000 }}>
597	      {webglSupported && (
598	        <canvas ref={canvasRef} style={style} />
599	      )}
600	    </div>
601	  );
602	});
603	
604	NavLinkShaderOverlay.displayName = 'NavLinkShaderOverlay';
605	
606	export default NavLinkShaderOverlay;
