    mat2 rot = mat2(cos(swirlAngle), -sin(swirlAngle), sin(swirlAngle), cos(swirlAngle));
    vec2 p = rot * smokeUV;

    // Add subtle wave distortion
    p.y += sin(uv.x * 6.28 + flowTime * 3.0) * 0.2;
    p.x += cos(uv.y * 12.56 + flowTime * 2.0) * 0.1;

