    position: fixed;
    left: 0;
    right: 0;
    bottom: 0;
    z-index: 100;
    margin: 0;
    border: 0;
    border-top: 1px solid rgba(229, 232, 235, 0.7);
    border-radius: 1.25rem 1.25rem 0 0;
    background: rgba(255, 255, 255, 0.94);
    backdrop-filter: blur(14px);
    -webkit-backdrop-filter: blur(14px);
    box-shadow: 0 -8px 28px rgba(0, 0, 0, 0.08);
    padding: 0.7rem 1rem calc(0.7rem + env(safe-area-inset-bottom, 0px));
    flex-direction: row;
    align-items: center;
    gap: 0.6rem;
    flex-wrap: wrap;
  }
  .buyBoxSticky {
    /* Override the desktop sticky behavior — the fixed positioning above
       fully replaces it on mobile. */
    position: fixed;
    top: auto;
  }
  .buyBox > .qtyRow,
  .buyBox > .actions {
    display: contents;
  }
  .qtyLabel,
  .shipNote {
    display: none;
  }
  .cta {
    flex: 1;
    height: 48px;
    border-radius: 12px;
    font-size: 1rem;
  }
  .wish {
    width: 48px;
    height: 48px;
    border-radius: 12px;
    flex: 0 0 auto;
  }
  .feedback {
    /* Span the whole bar width on a wrapped second row so the message is
       still readable above the action row. */
    flex-basis: 100%;
    margin-top: 0;
  }

