'use client';

import { useEffect, useId, useRef } from 'react';
import { getWebGLContextManager } from '@/utils/webglContextManager';

// Same fragment-shader recipe as HeaderGLSLCanvas (ambient smoke + swirl
// on a transparent backdrop), wired up for continuous ambient flow rather
// than profile-menu-driven bursts. Sized dynamically to the parent so a
// fixed-position bar with arbitrary width gets full coverage.

const vsSource = `
  attribute vec2 a_pos;
  varying vec2 v_uv;
  void main() {
    v_uv = a_pos * 0.5 + 0.5;
    gl_Position = vec4(a_pos, 0.0, 1.0);
  }
`;

const fsSource = `
  precision highp float;
  varying vec2 v_uv;
  uniform float u_time;
  uniform vec2 u_res;

  float hash(vec2 p) {
    return fract(sin(dot(p, vec2(127.1,311.7))) * 43758.5453123);
  }
  float noise(vec2 p) {
    vec2 i = floor(p);
    vec2 f = fract(p);
    vec2 u = f * f * (3.0 - 2.0 * f);
    return mix(
      mix(hash(i), hash(i + vec2(1.0, 0.0)), u.x),
      mix(hash(i + vec2(0.0, 1.0)), hash(i + vec2(1.0, 1.0)), u.x),
    u.y);
  }
  float fbm(vec2 p) {
    float v = 0.0;
    float a = 0.5;
    for(int i = 0; i < 5; i++) {
      v += a * noise(p);
      p = 2.0 * p + vec2(cos(u_time * 0.2), sin(u_time * 0.3));
      a *= 0.5;
    }
    return v;
  }

  void main() {
    vec2 uv = (v_uv - 0.5) * vec2(u_res.x / u_res.y, 1.0);

    // Match the header's ZOOM EFFECT for pattern parity.
    uv *= 0.4;

    // Continuous ambient flow — no interaction-time decay. The header
    // uses an exponential burst tied to profile-menu changes; the buy
    // bar should breathe steadily, so we drive flowTime from u_time
    // directly with a calm multiplier.
    float flowTime = u_time * 0.45;

    vec2 accumulatedFlow = vec2(
      flowTime * 1.0,
      -flowTime * 0.3
    );

    vec2 flowingUV = uv * 1.5 + accumulatedFlow;

    float angleNoise = fbm(flowingUV);
    float swirlAngle = (angleNoise - 0.5) * 3.1415;
    mat2 rot = mat2(cos(swirlAngle), -sin(swirlAngle), sin(swirlAngle), cos(swirlAngle));
    vec2 p = rot * uv;

    p += vec2(
      sin((uv.y + flowTime) * 3.0) * 0.25 + flowTime * 0.3,
      cos((uv.x + accumulatedFlow.x) * 3.0) * 0.2
    );

    float d = fbm(p * 1.3 + accumulatedFlow);
    d *= 0.7;
    float alpha = smoothstep(0.3, 0.6, d);

    // Soft horizontal vignette so the smoke fades into the bar's edges
    // and doesn't clip hard against the rounded corners.
    float edgeFade = smoothstep(0.0, 0.08, v_uv.x) * smoothstep(1.0, 0.92, v_uv.x);

    float final_mask = alpha * edgeFade;

    vec3 fluid = vec3(0.15, 0.2, 0.25);
    gl_FragColor = vec4(fluid, final_mask * 0.7);
  }
`;

const BuyBarShaderCanvas = () => {
