/* Header styles */
.header {
  padding: 1rem 2rem;
  width: 90%;
  border: 1.5px solid rgba(229, 232, 235, 0.5);
  margin-left: 5%;
  display: flex;
  justify-content: space-between;
  align-items: center;
  height: 65px;
  position: fixed;
  top: 1rem;
  left: 0;
  right: 0;
  z-index: 1000;
  background: transparent;
  backdrop-filter: blur(12px);
  -webkit-backdrop-filter: blur(12px);
  transition: all 0.5s cubic-bezier(0.175, 0.885, 0.32, 1.275);
  margin-left: auto;
  margin-right: auto;
  overflow: hidden;
  box-shadow: 0 8px 32px rgba(0, 0, 0, 0.1), 0 6px 6px rgba(0, 0, 0, 0.05);
  border-radius: 18px;
}

.brandContainer {
  display: flex;
  align-items: center;
  gap: 0.5rem;
  position: relative;
  z-index: 30;
}

.brand {
  font-size: 1.25rem;
  font-weight: 600;
  color: #000000;
  letter-spacing: -0.01em;
  transition: all 0.3s ease;
}

.dropdown {
  display: flex;
  align-items: center;
  margin-left: 0.25rem;
}

.navContainer {
  display: flex;
  align-items: center;
  position: relative;
  z-index: 30;
  min-height: 24px;
  min-width: 250px;
  transition: min-width 0.3s ease;
}

.profileMenuOpen {
  min-width: 480px;
}

.navLinksWrapper {
  display: flex;
  align-items: center;
  gap: 2rem;
  position: absolute;
  left: 0;
  white-space: nowrap;
}

.profileMenuWrapper {
  display: flex;
  align-items: center;
  gap: 1.5rem;
  position: absolute;
  left: 0;
  white-space: nowrap;
}

.navLink {
  font-size: 0.9375rem;
  font-weight: 500;
  color: #000000;
  transition: all 0.3s cubic-bezier(0.4, 0, 0.2, 1);
  position: relative;
}

.navLink:hover {
  color: #333333;
  transform: translateY(-1px);
}

/* Removed CSS underline - replaced with GLSL smoke effect */

.logoutLink {
  font-size: 0.9375rem;
  font-weight: 500;
  color: #dc2626;
  transition: all 0.3s cubic-bezier(0.4, 0, 0.2, 1);
  position: relative;
  background: transparent;
  border: none;
  cursor: pointer;
  padding: 0;
  text-align: left;
}

.logoutLink:hover {
  color: #b91c1c;
  transform: translateY(-1px);
}

/* Removed CSS underline for logout - replaced with GLSL smoke effect */

.iconButton {
  display: flex;
  align-items: center;
  justify-content: center;
  cursor: pointer;
  padding: 0.65rem;
  color: #000000;
  transition: all 0.3s cubic-bezier(0.175, 0.885, 0.32, 1.275);
  position: relative;
  z-index: 30;
  width: 38px;
  height: 38px;
}

.rightSection {
  display: flex;
