/* BUY BAR — floats as a pill above the viewport bottom on mobile. The
   blur recipe mirrors the Header exactly (transparent bg + blur(12px)
   backdrop-filter + same border / shadow). The inner `qtyRow` and
   `actions` collapse via `display: contents` so their children become
   direct flex items of the bar, giving us a single row:
   [qty stepper] [Add to Cart] [wishlist heart]. */
.buyBox {
  position: fixed;
  left: 0.5rem;
  right: 0.5rem;
  bottom: calc(0.75rem + env(safe-area-inset-bottom, 0px));
  z-index: 100;
  margin: 0;
  /* Header parity: same border, radius, shadow, and frosted blur. */
  border: 1.5px solid rgba(229, 232, 235, 0.5);
  border-radius: 18px;
  background: transparent;
  backdrop-filter: blur(12px);
  -webkit-backdrop-filter: blur(12px);
  box-shadow: 0 8px 32px rgba(0, 0, 0, 0.1), 0 6px 6px rgba(0, 0, 0, 0.05);
  overflow: hidden;
  padding: 0.7rem 1rem;
  flex-direction: row;
  align-items: center;
  gap: 0.6rem;
  flex-wrap: wrap;
}

input.new_string:
/* BUY BAR — floats as a pill above the viewport bottom on mobile. The
   glass recipe mirrors the Header exactly: 3 stacked backdrop layers
   (blur(12px) base + blur(2px) with #glass-distortion turbulence + a
   blur(2px) white tint at 25%). The inner `qtyRow` and `actions`
   collapse via `display: contents` so their children become direct
   flex items of the bar, giving us a single row:
   [qty stepper] [Add to Cart] [wishlist heart]. */
.buyBox {
  position: fixed;
  left: 0.5rem;
  right: 0.5rem;
  bottom: calc(0.75rem + env(safe-area-inset-bottom, 0px));
  z-index: 100;
  margin: 0;
  /* Header parity: same border, radius, shadow, base blur. */
  border: 1.5px solid rgba(229, 232, 235, 0.5);
  border-radius: 18px;
  background: transparent;
  backdrop-filter: blur(12px);
  -webkit-backdrop-filter: blur(12px);
  box-shadow: 0 8px 32px rgba(0, 0, 0, 0.1), 0 6px 6px rgba(0, 0, 0, 0.05);
  overflow: hidden;
  /* New stacking context so the glass pseudo-layers (negative z-index)
     sit behind the content without escaping the container. */
  isolation: isolate;
  padding: 0.7rem 1rem;
  flex-direction: row;
  align-items: center;
  gap: 0.6rem;
  flex-wrap: wrap;
}
/* Glass layer 1: small blur + SVG glass-distortion turbulence. The
   #glass-distortion filter is injected by the Header component on
   every page, so it's available to reference here. */
.buyBox::before {
  content: "";
  position: absolute;
  inset: 0;
  z-index: -2;
  backdrop-filter: blur(2px);
  -webkit-backdrop-filter: blur(2px);
  filter: url(#glass-distortion);
  pointer-events: none;
  border-radius: inherit;
}
/* Glass layer 2: white tint + small blur for the milk-glass frostiness. */
.buyBox::after {
  content: "";
  position: absolute;
  inset: 0;
  z-index: -1;
  background-color: rgba(255, 255, 255, 0.25);
  backdrop-filter: blur(2px);
  -webkit-backdrop-filter: blur(2px);
  pointer-events: none;
  border-radius: inherit;
}

